import React, { useState, useEffect } from 'react';
import useGetDate from '../Hooks/useGetDate';
import useGetSingleAPOD from '../Hooks/useGetSingleAPOD';

const Single = () => {

  const [apod, setApod] = useState(null);
  const [err, setErr] = useState(null);
  const [userDate, setUserDate] = useState(null);

  // const data = useGetSingleAPOD(today);

  useEffect(() => {
    let date = new Date();
    const today = useGetDate(date);
    setUserDate(today);
  }, []);

  // useEffect(() => {

  //   if (!data) {
  //     return 
  //   } else if (data.error) {
  //     setErr(data);
  //   } else {
  //     setApod(data);
  //   }

  // }, [data]);

  return (
    <div className='single-div'>
      <header className='single-header'>
        <h1>Single APOD</h1>
        <p>Select a single date or scroll with the buttons</p>
      </header>
      <div className="single-form-wrap">
          <form>
            <div className="start-container">
              <label htmlFor="start">Your date 
              (earliest date: 06-16-1995): </label>
              {/* TODO add value and onchange to set date state */}
              <input type="date" id="start" name="apod-start" min="1995-06-16" max={today} value={userDate &&userDate}/>
            </div>   

            {/* TODO add onchange */}
            <button className="update-btn">Update pictures</button>
          </form>
        </div>
      {/* <div className="test">
        {err 
        ? err.error
        : 'Loading...'
      }
      </div> */}
    </div>
  )
}

export default Single
